tsfunction countTerrain(gs: GameState, terrain: string): number {
  let count = 0;
  for (let y = 0; y < MAP_H; y++)
    for (let x = 0; x < MAP_W; x++)
      if (getTile(gs.tiles, x, y)?.terrain === terrain) count++;
  return count;
}

function getAvgFertility(gs: GameState): number {
  let total = 0, count = 0;
  for (let y = 0; y < MAP_H; y++)
    for (let x = 0; x < MAP_W; x++) {
      const t = getTile(gs.tiles, x, y);
      if (t) { total += t.fertility; count++; }
    }
  return count > 0 ? total / count : 0;
}
